use std::collections::HashMap;

fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let mut depth_memo: HashMap<i64, i64> = HashMap::new();

    fn get_popcount_depth(x: i64, memo: &mut HashMap<i64, i64>) -> i64 {
        if let Some(&depth) = memo.get(&x) {
            return depth;
        }
        let original_x = x;
        let mut current = x;
        let mut depth = 0;
        while current != 1 {
            current = current.count_ones() as i64;
            depth += 1;
        }
        memo.insert(original_x, depth);
        depth
    }

    let mut depths: Vec<i64> = nums.iter().map(|&x| get_popcount_depth(x, &mut depth_memo)).collect();
    let mut answer = Vec::new();

    for query in queries {
        if query[0] == 1 {
            let l = query[1] as usize;
            let r = query[2] as usize;
            let k = query[3];
            let count = (l..=r).filter(|&i| depths[i] == k).count() as i64;
            answer.push(count);
        } else if query[0] == 2 {
            let idx = query[1] as usize;
            let val = query[2];
            depths[idx] = get_popcount_depth(val, &mut depth_memo);
        }
    }

    answer
}
